const raw  = $input.first().json;
const body = raw.body || raw;
const entry  = (body.entry || [])[0];
const change = (entry && entry.changes || [])[0];
const value  = change && change.value;
const msgs   = (value && value.messages) || [];
if (!msgs.length) return [{ json: { type: 'status_update' } }];
const msg = msgs[0];
const common = {
  type: 'message', phone: '+' + msg.from, raw_from: msg.from, message_id: msg.id,
  sender_name: ((value && value.contacts) || [])[0] && ((value.contacts)[0].profile||{}).name || '',
  timestamp: msg.timestamp, phone_number_id: (value && value.metadata && value.metadata.phone_number_id) || '',
  channel: 'whatsapp', waba_id: (entry && entry.id) || ''
};
if (msg.type === 'text')  return [{ json: { ...common, message_text: msg.text.body, needs_media: false } }];
if (msg.type === 'audio') return [{ json: { ...common, message_text: '', needs_media: true, media_kind: 'audio', media_id: (msg.audio||{}).id, media_mime: (msg.audio||{}).mime_type || 'audio/ogg' } }];
if (msg.type === 'image') return [{ json: { ...common, message_text: (msg.image||{}).caption || '', needs_media: true, media_kind: 'image', media_id: (msg.image||{}).id, media_mime: (msg.image||{}).mime_type || 'image/jpeg' } }];
return [{ json: { type: 'unsupported_media', from: '+' + msg.from, media_type: msg.type } }];

const rows = $input.all();
const ctx  = $('Parse Request').first().json;
if (rows.length === 0 || !rows[0].json || !rows[0].json.clinic_id) {
  return [];
}
return [{ json: { ...ctx, clinic_id: rows[0].json.clinic_id } }];

const rows = $input.all();
const ctx  = $('S4 Clinic Context').first().json;
// Fail-open: DB error ? allow (don't block prod on transient DB hiccup)
const firstRow = rows.length > 0 ? rows[0].json : {};
const enabled  = firstRow.error ? true : (firstRow.enabled === true);
return [{ json: { ...ctx, sura_ai_enabled: enabled } }];

const ctx = $json;
const clinicName = ctx.clinic_name_ar || ctx.clinic_name || 'عذراً، الخدمة غير متاحة حالياً. يرجى التواصل مع العيادة مباشرة.';
return [{ json: {
  ...ctx,
  to:     ctx.phone,
  body:   'عذراً، الخدمة غير متاحة حالياً. يرجى التواصل مع العيادة مباشرة.' + clinicName + ' ??????.',
  sender: 'sura'
} }];

const ctx = $('S6 Save User Msg').first().json;
let _hist = {}; try { _hist = $('Load Patient History').first().json || {}; } catch(e) {}
const esc = s => String(s == null ? '' : s).replace(/{/g, '{{').replace(/}/g, '}}'); // protect LangChain templating from clinic free-text
const wh = ctx.working_hours || {};
const open = String(wh.open || '09:00'), close = String(wh.close || '18:00');
const closedWd = Array.isArray(wh.closed_weekdays) ? wh.closed_weekdays : [];
const tz = ctx.clinic_timezone || 'Asia/Muscat';
const _lc = String(ctx.message_text||'').replace(/\[ملاحظة نظام[\s\S]*?\]/g,''); const _uL = (_lc.match(/[A-Za-z]/g)||[]).length; const _uA = (_lc.match(/[؀-ۿ]/g)||[]).length; const userLang = _uL > _uA ? 'الإنجليزية' : 'العربية';

const now = new Date();
const nice = new Intl.DateTimeFormat('ar', { timeZone:tz, weekday:'long', day:'numeric', month:'long', hour:'numeric', minute:'2-digit', hour12:true }).format(now);
const todayISO = new Intl.DateTimeFormat('en-CA', { timeZone:tz, year:'numeric', month:'2-digit', day:'2-digit' }).format(now);
const pp = new Intl.DateTimeFormat('en-US', { timeZone:tz, weekday:'short', hour:'2-digit', hour12:false }).formatToParts(now);
const dayShort = (pp.find(x=>x.type==='weekday')||{}).value;
const hour24 = parseInt((pp.find(x=>x.type==='hour')||{}).value || '0', 10);
const openH = parseInt(open.split(':')[0] || '9', 10), closeH = parseInt(close.split(':')[0] || '18', 10);
const isOpen = !closedWd.includes(dayShort) && hour24 >= openH && hour24 < closeH;
const status = 'الوقت الآن بالضبط: ' + nice + ' (توقيت ' + tz + '). تاريخ اليوم ISO: ' + todayISO + '. حالة العيادة الآن: ' + (isOpen ? 'مفتوحة' : 'مغلقة');

const _v = Number(_hist.visits||0), _ns = Number(_hist.no_shows||0);
let histSection = '';
if (_v > 0) {
  const lv = _hist.last_visit ? new Intl.DateTimeFormat('ar',{timeZone:tz,day:'numeric',month:'long',year:'numeric'}).format(new Date(_hist.last_visit)) : '';
  histSection = '[سجل المريض — استعمليه بذكاء للترحيب والتخصيص، ولا تُفصحي عن الأرقام إلا إن سأل]\n' +
    'مريض حالي معروف: ' + _v + ' زيارة سابقة' + (lv ? ('، آخر زيارة ' + lv) : '') + '.' +
    (_hist.services ? (' خدماته السابقة: ' + esc(_hist.services) + '.') : '') +
    (_ns > 0 ? (' سجّل ' + _ns + ' غياباً سابقاً — ذكّريه بلطف بأهمية تأكيد الموعد والحضور.') : '');
} else {
  histSection = '[سجل المريض]\nمريض جديد (لا زيارات سابقة) — رحّبي به ترحيباً خاصاً بأول زيارة.';
}
const _next = _hist.next_upcoming ? new Intl.DateTimeFormat('ar',{timeZone:tz,weekday:'long',day:'numeric',month:'long',hour:'numeric',minute:'2-digit',hour12:true}).format(new Date(_hist.next_upcoming)) : '';
if (_next) histSection += '\n لديه موعد قادم مؤكد: ' + _next + '. إن سأل «متى موعدي» أخبريه به، ولا تحجزي موعداً جديداً إلا إن طلب صراحةً.';

let doctorsSection = '';
try {
  let docs = _hist.doctors_json;
  if (typeof docs === 'string') docs = JSON.parse(docs);
  if (Array.isArray(docs) && docs.length) {
    doctorsSection = '[أطباء العيادة والخدمات التي يقدّمها كل طبيب]\n' + docs.map(dd => '• ' + esc(dd.name_ar) + ': ' + (((dd.services)||[]).filter(Boolean).map(x=>esc(x)).join('، ') || 'خدمات عامة')).join('\n') +
      '\nإذا طلب المريض طبيباً بعينه اضبطي booking.doctor باسمه؛ وإلا اتركيه فارغاً وسيُسنَد تلقائياً أنسب طبيب متاح. لا تعِدي المريض بطبيب لا يقدّم الخدمة المطلوبة.';
  }
} catch(e) {}

const cur = ctx.currency === 'OMR' ? 'ر.ع' : (ctx.currency || '');
const fmtPrice = v => { const n = Number(v); return (ctx.currency === 'OMR' && !isNaN(n)) ? n.toFixed(3) : esc(v); };
const svcLines = (ctx.services||[]).map(s => '• ' + esc(s.name_ar) + ' — ' + fmtPrice(s.price) + ' ' + cur).join('\n') || '(لا توجد خدمات مسجّلة)';

// ── THE single editable place: each clinic's full System Message ──
let body = esc((ctx.sura_system_message || '').trim());
if (!body) {
  const CLINIC = esc(ctx.clinic_name_ar || ctx.clinic_name || 'العيادة');
  body = 'أنتِ «سُرى»، موظفة الاستقبال الذكية في ' + CLINIC + ' عبر واتساب. كوني دافئة، مهذبة، مقتضبة، واحترافية، وساعدي المريض في الاستفسارات وحجز المواعيد. لا تكشفي أنكِ ذكاء اصطناعي.';
}

const sp =
'أنتِ محرّك يولّد ردود «سُرى». مخرجك دائماً كائن JSON واحد فقط بلا أي نص خارجه إطلاقاً — حتى عند الترحيب أو تأكيد الحجز. كلام سُرى للمريض يوضع داخل الحقل response_ar فقط، والبنية الكاملة موضّحة في نهاية التعليمات.\n\n' +
'🌐 [اللغة — إلزامي وأولوية عليا]: لغة رسالة المريض الحالية هي ' + userLang + '. اكتب محتوى حقل response_ar بهذه اللغة حصراً — حتى لو كانت الرسالة تحية قصيرة مثل «hi» أو «hello» أو «نعم». لا تخلط اللغتين في رسالة واحدة.\n\n' +
'===== شخصية سُرى وتعليماتها وبياناتها (مرجع لصياغة response_ar) =====\n' +
body + '\n\n' +
'[الخدمات والأسعار — تُحدّث تلقائياً من النظام]\n' + svcLines + '\n\n' +
'[الوقت — تلقائي، ممنوع الحجز في الماضي]\n' + status + '\n\n' + histSection + '\n\n' +
(doctorsSection ? doctorsSection + '\n\n' : '') +
'[حقل booking — إلزامي في كل رد]\nاملئي حقل booking دائماً بما جمعتِه: service_ar (اسم الخدمة بالعربي كما في قائمة الأسعار أعلاه)، date بصيغة YYYY-MM-DD، time بصيغة HH:MM (٢٤ ساعة)، patient_name، و doctor (اسم الطبيب فقط إن طلبه المريض صراحةً وإلا فارغ)، و action بإحدى القيم فقط: "book" لحجز جديد، أو "cancel" لإلغاء موعد قائم، أو "reschedule" لتغيير/تأجيل موعد قائم إلى وقت جديد، أو "waitlist" لتسجيل المريض في قائمة الانتظار عند رغبته حين يكون الوقت المطلوب محجوزاً، أو "confirm" لتأكيد حضور المريض لموعده القائم رداً على تذكير (الافتراضي "book" — لا تستخدمي "reschedule" إلا إذا كان للمريض موعد قائم يريد نقله). اتركي ما لم يُذكر بعد فارغاً "". احسبي التاريخ من تاريخ اليوم ISO أعلاه («بكرة»=+١، واسم اليوم=أقرب تاريخ قادم يحمله). اضبطي confirmed=true فقط في الرد الذي يوافق فيه المريض نهائياً وتكون الحقول الأربعة مكتملة والوقت ليس ماضياً؛ غير ذلك confirmed=false.\nمهم جداً: إذا سبق أن تأكّد حجز في هذه المحادثة، اتركي confirmed=false في كل الرسائل التالية (شكر، تحية، يعطيك العافية، استفسار) — لا تعيدي الحجز إطلاقاً ما لم يطلب المريض موعداً جديداً مختلفاً صراحةً.\n' +
'[⚠️ تنسيق الإخراج — إلزامي بلا أي استثناء]\n' +
'أخرجي كائن JSON واحد صالحاً فقط لا غير. ممنوع منعاً باتاً أي نص أو شرح أو إيموجي خارج الـ JSON، حتى عند الترحيب أو تأكيد الحجز. ضعي كلامك للمريض داخل الحقل response_ar فقط. أي رد ليس JSON يُعدّ خطأ.\n' +
'البنية المطلوبة بالضبط:\n' +
'{{"intent":"greeting|book_appointment|cancel_appointment|reschedule_appointment|check_status|inquiry_services|inquiry_pricing|inquiry_location|inquiry_hours|payment_inquiry|complaint|follow_up|emergency|off_topic|unclear","response_ar":"ردّك المقتضب بالعربية","confidence":0.0,"is_sensitive":false,"requires_hitl":false,"booking":{{"confirmed":false,"service_ar":"","date":"","time":"","patient_name":"","doctor":""}}}}';

return [{ json: {
  ...ctx, system_prompt: sp, user_message: ctx.message_text, session_id: ctx.session_id,
  clinic_id: ctx.clinic_id, phone: ctx.phone, patient_id: ctx.patient_id,
  clarification_count: ctx.clarification_count || 0, booking_in_progress: ctx.booking_in_progress || false,
  clinic_name: ctx.clinic_name_ar || ctx.clinic_name
}}];

const out = $json.output;
const ctx = $('Build AI Context').first().json;
function escInStr(s){ let o='',q=false,e=false; for(let i=0;i<s.length;i++){const ch=s[i]; if(e){o+=ch;e=false;continue;} if(ch==='\\'){o+=ch;e=true;continue;} if(ch==='"'){q=!q;o+=ch;continue;} if(q&&ch==='\n'){o+='\\n';continue;} if(q&&ch==='\r'){o+='\\r';continue;} if(q&&ch==='\t'){o+='\\t';continue;} o+=ch; } return o; }
function toObj(x){ if(x&&typeof x==='object')return x; let s=String(x==null?'':x).trim(); const a=s.indexOf('{'),b=s.lastIndexOf('}'); if(a>=0&&b>a)s=s.slice(a,b+1); try{return JSON.parse(s);}catch(e){} try{return JSON.parse(escInStr(s));}catch(e){} const m=s.match(/"response_ar"\s*:\s*"([\s\S]*?)"\s*[,}]/); return {intent:'inquiry',response_ar:m?m[1].replace(/\\n/g,'\n'):s,confidence:0.7,booking:{}}; }
const parsed = toObj(out) || {};
const bk = (parsed.booking && typeof parsed.booking==='object') ? parsed.booking : {};
const it = String(parsed.intent||'').toLowerCase();
let act = String(bk.action||'').toLowerCase();
if (!['book','cancel','reschedule','waitlist','confirm'].includes(act)) act = '';
if (!act) act = it.includes('reschedul') ? 'reschedule' : (it.includes('cancel') ? 'cancel' : ((it.includes('wait')) ? 'waitlist' : 'book'));
if (act === 'book' && it.includes('reschedul')) act = 'reschedule';
if (act === 'book' && it.includes('cancel')) act = 'cancel';
if (act === 'book' && it.includes('wait')) act = 'waitlist';
if (act === 'book' && (it.includes('attend') || it.includes('confirm_attend'))) act = 'confirm';
const _um = String(ctx.message_text||'');
const _attNeg = /(ما|مو|مب|لن|ماني|ما\s*راح)\s*(راح\s*)?(ب?أ?حضر|سأحضر|أجي|بجي)/.test(_um);
const _attPos = /(بحضر|سأحضر|سوف أحضر|راح أجي|بجي|حاضر أجي|أكّد حضور|اكد حضور|أؤكد حضور|تأكيد الحضور|ثبّت موعد|ثبت موعد)/.test(_um);
if (act === 'book' && _attPos && !_attNeg) act = 'confirm';
const is_emergency = (parsed.is_emergency===true) || it.includes('emerg') || it.includes('urgent');
const is_complaint = (parsed.is_complaint===true) || it.includes('complaint') || it.includes('شكو');
function _sl(s){ s=String(s||''); const ar=(s.match(/[\u0600-\u06FF]/g)||[]).length, la=(s.match(/[A-Za-z]/g)||[]).length; return la>ar?'en':'ar'; }
const lang = (_sl(String(ctx.message_text||'').replace(/\[ملاحظة نظام[\s\S]*?\]/g,''))==='en' || _sl(parsed.response_ar)==='en') ? 'en' : 'ar';
return [{ json: { ...ctx, lang,
  intent: parsed.intent||'unclear', response_ar: parsed.response_ar||'', confidence: parsed.confidence??0.0,
  is_sensitive: parsed.is_sensitive??false, requires_hitl: parsed.requires_hitl??false, is_emergency, is_complaint,
  booking_confirmed: bk.confirmed===true, b_action: act,
  b_service_ar: bk.service_ar||'', b_date: bk.date||'', b_time: bk.time||'', b_patient_name: bk.patient_name||'', b_doctor: bk.doctor||'',
  raw_ai_output: (typeof out==='string'?out:JSON.stringify(out)) } }];

const c = $json;
const action = c.b_action || 'book';
const esc = s => String(s||'').replace(/'/g, "''");
const CID = c.clinic_id, PID = c.patient_id;
const reqDoctor = esc(String(c.b_doctor||'').trim());
const services = Array.isArray(c.services)?c.services:[];
const want = String(c.b_service_ar||'').trim();
let svc = services.find(s=>s.name_ar===want) || services.find(s=>want&&s.name_ar&&(want.includes(s.name_ar)||s.name_ar.includes(want))) || null;
const _en = c.lang==='en'; const dexpr = _en ? 'COALESCE(u.name,u.name_ar)' : 'COALESCE(u.name_ar,u.name)'; const svcName = (_en ? (svc && (svc.name||svc.name_ar)) : (svc && svc.name_ar)) || (c.b_service_ar||'');
let t = String(c.b_time||'').trim(); let m = t.match(/^(\d{1,2})(?::(\d{2}))?$/);
let hh = m?String(m[1]).padStart(2,'0'):''; let mm=(m&&m[2])?m[2]:'00';
const dateOk = /^\d{4}-\d{2}-\d{2}$/.test(String(c.b_date||''));
const slot_time = (dateOk&&hh)?(c.b_date+'T'+hh+':'+mm+':00+04:00'):'';
const future = slot_time?(new Date(slot_time).getTime()>Date.now()-3600000):false;
const name = esc(c.b_patient_name);
const dur = svc?parseInt(svc.dur||30,10):30;
const wh = c.working_hours||{};
const openH = parseInt(String(wh.open||'09:00').split(':')[0],10)||9;
const closeH = parseInt(String(wh.close||'18:00').split(':')[0],10)||18;
const pad = x=>String(x).padStart(2,'0');
const openTs=dateOk?(c.b_date+'T'+pad(openH)+':00:00+04:00'):''; const closeTs=dateOk?(c.b_date+'T'+pad(closeH)+':00:00+04:00'):'';
const dayStart=dateOk?(c.b_date+'T00:00:00+04:00'):''; const dayEnd=dateOk?(c.b_date+'T23:59:59+04:00'):'';
const IV = dur + " || ' minutes'";
const NIL='00000000-0000-0000-0000-000000000000';
const MCT = "'"+slot_time+"'::timestamptz AT TIME ZONE 'Asia/Muscat'";
const schedOkU = " AND (NOT EXISTS (SELECT 1 FROM public.doctor_schedules ss WHERE ss.doctor_id=u.id AND ss.is_active) OR EXISTS (SELECT 1 FROM public.doctor_schedules ss WHERE ss.doctor_id=u.id AND ss.is_active AND ss.day_of_week::text=to_char("+MCT+",'fmday') AND ("+MCT+")::time >= ss.start_time AND (("+MCT+")::time + ("+IV+")::interval) <= ss.end_time))";
const leaveOkU = " AND NOT EXISTS (SELECT 1 FROM public.clinic_holidays hh WHERE hh.clinic_id='"+CID+"'::uuid AND hh.holiday_date=("+MCT+")::date AND (hh.applies_to_all_doctors OR hh.doctor_id=u.id))";
const gsAvail = " AND (NOT EXISTS (SELECT 1 FROM public.doctor_schedules ss WHERE ss.doctor_id=c3.doctor_id AND ss.is_active) OR EXISTS (SELECT 1 FROM public.doctor_schedules ss WHERE ss.doctor_id=c3.doctor_id AND ss.is_active AND ss.day_of_week::text=to_char(gs AT TIME ZONE 'Asia/Muscat','fmday') AND (gs AT TIME ZONE 'Asia/Muscat')::time >= ss.start_time AND ((gs AT TIME ZONE 'Asia/Muscat')::time + ("+IV+")::interval) <= ss.end_time)) AND NOT EXISTS (SELECT 1 FROM public.clinic_holidays hh WHERE hh.clinic_id='"+CID+"'::uuid AND hh.holiday_date=(gs AT TIME ZONE 'Asia/Muscat')::date AND (hh.applies_to_all_doctors OR hh.doctor_id=c3.doctor_id))";
let sql;
if (action==='cancel' && CID && PID) {
  sql = "WITH tgt AS (SELECT id, slot_time FROM public.appointments WHERE clinic_id='"+CID+"'::uuid AND patient_id='"+PID+"'::uuid AND deleted_at IS NULL AND status IN ('scheduled','confirmed','checked_in') AND slot_time > now() ORDER BY slot_time LIMIT 1), " +
        "upd AS (UPDATE public.appointments SET status='cancelled', cancelled_at=now(), cancellation_reason='إلغاء عبر سُرى (واتساب)' WHERE id=(SELECT id FROM tgt) RETURNING id, slot_time) " +
        "SELECT CASE WHEN EXISTS(SELECT 1 FROM upd) THEN 'cancelled' ELSE 'nothing_to_cancel' END AS booking_status, (SELECT id::text FROM upd) AS appointment_id, (SELECT slot_time::text FROM upd) AS slot_time_out, NULL::text AS alternatives, NULL::text AS doctor_name;";
} else if (action==='confirm' && CID && PID) {
  sql = "WITH tgt AS (SELECT id, slot_time, doctor_id, status FROM public.appointments WHERE clinic_id='"+CID+"'::uuid AND patient_id='"+PID+"'::uuid AND deleted_at IS NULL AND status IN ('scheduled','confirmed') AND slot_time > now() ORDER BY slot_time LIMIT 1), " +
        "upd AS (UPDATE public.appointments SET status='confirmed', updated_at=now() WHERE id=(SELECT id FROM tgt) AND (SELECT status FROM tgt)='scheduled' RETURNING id) " +
        "SELECT CASE WHEN EXISTS(SELECT 1 FROM tgt) THEN 'attendance_confirmed' ELSE 'nothing_to_confirm' END AS booking_status, (SELECT id::text FROM tgt) AS appointment_id, (SELECT slot_time::text FROM tgt) AS slot_time_out, NULL::text AS alternatives, (SELECT "+dexpr+" FROM public.tawd_staff_users u WHERE u.id=(SELECT doctor_id FROM tgt)) AS doctor_name;";
} else if (action==='waitlist' && svc && svc.id && CID && PID) {
  const df = dateOk ? ("'"+c.b_date+"'::date") : "NULL::date";
  const pw = hh ? ("'[\""+hh+":"+mm+"\"]'::jsonb") : "'[]'::jsonb";
  const stout = dateOk ? ("'"+c.b_date+"T00:00:00+04:00'") : "NULL::text";
  sql = "WITH dup AS (SELECT id FROM public.appointment_waitlist WHERE clinic_id='"+CID+"'::uuid AND patient_id='"+PID+"'::uuid AND service_id='"+svc.id+"'::uuid AND status IN ('waiting','offered') LIMIT 1), " +
        "ins AS (INSERT INTO public.appointment_waitlist (clinic_id,patient_id,service_id,doctor_id,desired_from,desired_to,pref_windows,status) SELECT '"+CID+"'::uuid,'"+PID+"'::uuid,'"+svc.id+"'::uuid,NULL,"+df+","+df+","+pw+",'waiting' WHERE NOT EXISTS(SELECT 1 FROM dup) RETURNING id) " +
        "SELECT CASE WHEN EXISTS(SELECT 1 FROM ins) THEN 'waitlisted' WHEN EXISTS(SELECT 1 FROM dup) THEN 'already_waitlisted' ELSE 'error' END AS booking_status, (SELECT id::text FROM ins) AS appointment_id, "+stout+" AS slot_time_out, NULL::text AS alternatives, NULL::text AS doctor_name;";
} else if (action==='reschedule' && slot_time && future && dateOk && CID && PID) {
  const rSvcId = (svc && svc.id) ? svc.id : '';
  const rDur = svc ? dur : 0;
  const IVr = "((SELECT dur FROM newsvc)||' minutes')::interval";
  sql = "WITH tgt AS (SELECT id, slot_time, service_id, duration_minutes, doctor_id FROM public.appointments WHERE clinic_id='"+CID+"'::uuid AND patient_id='"+PID+"'::uuid AND deleted_at IS NULL AND status IN ('scheduled','confirmed','checked_in') AND slot_time > now() ORDER BY slot_time LIMIT 1), " +
        "newsvc AS (SELECT COALESCE(NULLIF('"+rSvcId+"','')::uuid,(SELECT service_id FROM tgt)) AS sid, COALESCE(NULLIF("+rDur+",0),(SELECT duration_minutes FROM tgt),30) AS dur), " +
